import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

import Login from "./pages/auth/Login";
import Dashboard from "./pages/dashboard/UserDashboard";
import BrowseResources from "./pages/resources/BrowseResources";
import ResourceDetails from "./pages/resources/ResourceDetails";
import MyResources from "./pages/myresources/MyResources";
import RequestHistory from "./pages/requests/RequestHistory";
import Notifications from "./pages/notifications/Notifications";
import Profile from "./pages/profile/Profile";

function App() {
  return (
    <Router>
      <Routes>

        <Route path="/" element={<Login />} />

        <Route path="/dashboard" element={<Dashboard />} />

        <Route path="/resources" element={<BrowseResources />} />

        <Route path="/resource/:id" element={<ResourceDetails />} />

        <Route path="/my-resources" element={<MyResources />} />

        <Route path="/requests" element={<RequestHistory />} />

        <Route path="/notifications" element={<Notifications />} />

        <Route path="/profile" element={<Profile />} />

      </Routes>
    </Router>
  );
}

export default App;
